class OnPointChat {
    constructor() {
        this.messages = [];
        this.isOpen = false;
        this.isTyping = false;
        this.init();
    }

    init() {
        this.createWidget();
        this.bindEvents();
    }

    createWidget() {
        const widget = document.createElement('div');
        widget.innerHTML = `
            <div class="chat-widget" id="chat-widget">
                <button class="chat-toggle" id="chat-toggle" aria-label="Open chat">
                    <span class="chat-toggle__icon"><svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="#ffffff" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"><path d="M21 15a2 2 0 01-2 2H7l-4 4V5a2 2 0 012-2h14a2 2 0 012 2z"/><path d="M8 10h.01M12 10h.01M16 10h.01" stroke-width="2.5"/></svg></span>
                    <span class="chat-toggle__close">✕</span>
                    <span class="chat-toggle__pulse"></span>
                </button>
                
                <div class="chat-window" id="chat-window">
                    <div class="chat-header">
                        <div class="chat-header__info">
                            <div class="chat-header__avatar">OP</div>
                            <div>
                                <div class="chat-header__name">On Point AI</div>
                                <div class="chat-header__status">Online — Ask us anything!</div>
                            </div>
                        </div>
                        <button class="chat-header__close" id="chat-close">✕</button>
                    </div>
                    
                    <div class="chat-messages" id="chat-messages">
                        <div class="chat-message chat-message--bot">
                            <div class="chat-message__bubble">
                                Hey! 👋 I'm the On Point AI assistant. Got questions about web design, SEO, pricing, or our services? Fire away!
                            </div>
                        </div>
                    </div>
                    
                    <div class="chat-input">
                        <input type="text" id="chat-input" placeholder="Type your message..." autocomplete="off">
                        <button id="chat-send" aria-label="Send message">
                            <svg viewBox="0 0 24 24" width="20" height="20"><path d="M22 2L11 13M22 2l-7 20-4-9-9-4 20-7z" stroke="currentColor" stroke-width="2" fill="none" stroke-linecap="round" stroke-linejoin="round"/></svg>
                        </button>
                    </div>
                </div>
            </div>
        `;
        document.body.appendChild(widget);
    }

    bindEvents() {
        const toggle = document.getElementById('chat-toggle');
        const close = document.getElementById('chat-close');
        const input = document.getElementById('chat-input');
        const send = document.getElementById('chat-send');
        const widget = document.getElementById('chat-widget');

        toggle.addEventListener('click', () => this.toggle());
        close.addEventListener('click', () => this.toggle());
        send.addEventListener('click', () => this.sendMessage());
        input.addEventListener('keydown', (e) => {
            if (e.key === 'Enter' && !e.shiftKey) {
                e.preventDefault();
                this.sendMessage();
            }
        });
    }

    toggle() {
        this.isOpen = !this.isOpen;
        const widget = document.getElementById('chat-widget');
        widget.classList.toggle('chat-widget--open', this.isOpen);
        if (this.isOpen) {
            document.getElementById('chat-input').focus();
        }
    }

    async sendMessage() {
        const input = document.getElementById('chat-input');
        const text = input.value.trim();
        if (!text || this.isTyping) return;

        input.value = '';
        this.addMessage(text, 'user');
        this.messages.push({ role: 'user', content: text });

        this.isTyping = true;
        this.showTyping();

        try {
            const response = await fetch(CHATBOT_CONFIG.apiUrl, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${CHATBOT_CONFIG.apiKey}`,
                    'HTTP-Referer': 'https://onpoint.com',
                    'X-Title': 'On Point Chatbot'
                },
                body: JSON.stringify({
                    model: CHATBOT_CONFIG.model,
                    messages: [
                        { role: 'system', content: CHATBOT_CONFIG.systemPrompt },
                        ...this.messages.slice(-10)
                    ],
                    max_tokens: 300,
                    temperature: 0.7
                })
            });

            const data = await response.json();
            const reply = data.choices?.[0]?.message?.content || "Sorry, I'm having a moment. Try again or reach out to us at hello@onpointfl.com!";
            
            this.messages.push({ role: 'assistant', content: reply });
            this.removeTyping();
            this.addMessage(reply.replace(/\[LEAD\].*$/m, '').trim(), 'bot');
            
            // Chatbot no longer tries to email leads directly.
            // Instead, the system prompt directs users to the contact form.
        } catch (err) {
            this.removeTyping();
            this.addMessage("Oops, something went wrong. You can reach us directly at hello@onpointfl.com or call (727) 279-5862!", 'bot');
        }

        this.isTyping = false;
    }

    addMessage(text, sender) {
        const container = document.getElementById('chat-messages');
        const msg = document.createElement('div');
        msg.className = `chat-message chat-message--${sender}`;
        msg.innerHTML = `<div class="chat-message__bubble">${this.escapeHtml(text)}</div>`;
        container.appendChild(msg);
        container.scrollTop = container.scrollHeight;
    }

    showTyping() {
        const container = document.getElementById('chat-messages');
        const typing = document.createElement('div');
        typing.className = 'chat-message chat-message--bot chat-typing';
        typing.innerHTML = `<div class="chat-message__bubble"><span class="typing-dots"><span>.</span><span>.</span><span>.</span></span></div>`;
        container.appendChild(typing);
        container.scrollTop = container.scrollHeight;
    }

    removeTyping() {
        const typing = document.querySelector('.chat-typing');
        if (typing) typing.remove();
    }

    escapeHtml(text) {
        const div = document.createElement('div');
        div.textContent = text;
        return div.innerHTML;
    }
}

document.addEventListener('DOMContentLoaded', () => {
    new OnPointChat();
});
